// ── Step 1: Collect ASINs from Amazon search pages via scrape.do ─────────────────────
// API: http://api.scrape.do/?url={encoded}&token={tok}&super=true&regionalGeoCode=europe
const cfg  = $input.first().json;
const tok  = cfg.scrapeDoToken;
const mp   = cfg.marketplace;
const kwds = cfg.keywords.split(',').map(k => k.trim()).filter(Boolean);
const maxN = parseInt(cfg.maxPerKeyword) || 50;

const DOMAINS = {
  'es':'amazon.es', 'de':'amazon.de', 'fr':'amazon.fr', 'it':'amazon.it',
  'co.uk':'amazon.co.uk', 'com':'amazon.com', 'ca':'amazon.ca', 'mx':'amazon.com.mx'
};
// scrape.do regionalGeoCode values for search API
const GEO_REGION = {
  'es':'europe', 'de':'europe', 'fr':'europe', 'it':'europe', 'co.uk':'europe',
  'com':'north_america', 'ca':'north_america', 'mx':'latin_america'
};
// scrape.do geocode values for PDP plugin
const GEO_CODE = {
  'es':'es', 'de':'de', 'fr':'fr', 'it':'it',
  'co.uk':'gb', 'com':'us', 'ca':'ca', 'mx':'mx'
};
// Default zipcodes required by PDP plugin per marketplace
const ZIPCODE = {
  'es':'28001', 'de':'10115', 'fr':'75001', 'it':'00187',
  'co.uk':'SW1A1AA', 'com':'10001', 'ca':'M5V3A8', 'mx':'06600'
};
const dom     = DOMAINS[mp]    || 'amazon.es';
const geoReg  = GEO_REGION[mp] || 'europe';
const geoCode = GEO_CODE[mp]   || 'es';
const zipcode = ZIPCODE[mp]    || '28001';
const lang    = mp !== 'co.uk' ? '&language=en' : '';

const seen = new Set();
const out  = [];

for (const kw of kwds) {
  const searchUrl = `https://www.${dom}/s?k=${encodeURIComponent(kw)}${lang}`;
  const qs = new URLSearchParams({
    url:             searchUrl,
    token:           tok,
    super:           'true',
    regionalGeoCode: geoReg,
  }).toString();

  console.log(`[ASIN] keyword=${kw}  url=${searchUrl}`);

  try {
    const html  = await this.helpers.httpRequest({ method: 'GET', url: `http://api.scrape.do/?${qs}` });
    const str   = typeof html === 'string' ? html : JSON.stringify(html);
    const parts = str.split('data-asin=');
    let cnt = 0;

    for (let i = 1; i < parts.length && cnt < maxN; i++) {
      const asin = parts[i].slice(1, 11);
      if (/^[A-Z0-9]{10}$/.test(asin) && !seen.has(asin)) {
        seen.add(asin);
        out.push({ asin, keyword: kw, marketplace: mp, domain: dom, token: tok, geoCode, zipcode, scraperUrl: cfg.scraperUrl, scraperApiKey: cfg.scraperApiKey });
        cnt++;
      }
    }
    console.log(`[ASIN] ${cnt} found for "${kw}"`);
  } catch (e) {
    console.error(`[ASIN] Failed for "${kw}": ${e.message}`);
  }
}

console.log(`[ASIN] Total unique ASINs: ${out.length}`);
return out.map(r => ({ json: r }));

// ── Step 2: Filter Amazon-sold products via scrape.do PDP plugin ─────────────────────
// PDP plugin: https://api.scrape.do/plugin/amazon/pdp
// Required params: token, asin, geocode, zipcode
// Returns structured JSON — we only use sold_by to detect Amazon-sold items.
// Non-Amazon ASINs are passed to our custom scraper in step 3.
const items   = $input.all();
const results = [];

console.log(`[PDP] Filtering ${items.length} ASINs for Amazon-sold...`);

for (const it of items) {
  const { asin, marketplace: mp, domain: dom, token: tok, geoCode, zipcode, scraperUrl, scraperApiKey } = it.json;

  const qs = new URLSearchParams({
    token:   tok,
    asin:    asin,
    geocode: geoCode,
    zipcode: zipcode,
  }).toString();

  console.log(`[PDP] ASIN: ${asin}  geocode=${geoCode}  zipcode=${zipcode}`);

  try {
    let data = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://api.scrape.do/plugin/amazon/pdp?${qs}`,
    });

    if (typeof data === 'string') { try { data = JSON.parse(data); } catch (_) {} }

    const soldBy     = String(data.sold_by || data.soldBy || data.seller?.name || '').toLowerCase();
    const amazonSold = soldBy.includes('amazon') || data.soldByAmazon === true;
    const sellerName = data.sold_by || data.soldBy || 'unknown';
    const productName = String(data.name || '').slice(0, 60);

    if (amazonSold) {
      console.log(`[PDP] ${asin} → sold by Amazon ("${sellerName}") — SKIP`);
    } else if (data.error) {
      console.warn(`[PDP] ${asin} → error: ${data.error} — passing through anyway`);
      results.push({ json: { asin, seller_name: 'unknown', marketplace: mp, scraperUrl, scraperApiKey } });
    } else {
      console.log(`[PDP] ${asin} → 3P seller: "${sellerName}"  product: ${productName}`);
      results.push({ json: { asin, seller_name: sellerName, marketplace: mp, scraperUrl, scraperApiKey } });
    }

  } catch (e) {
    console.error(`[PDP] ${asin} failed: ${e.message} — passing through anyway`);
    results.push({ json: { asin, seller_name: 'unknown', marketplace: mp, scraperUrl, scraperApiKey } });
  }
}

console.log(`[PDP] ${results.length} non-Amazon ASINs to scrape`);
return results;

// ── Step 3: Scrape full seller info via local custom scraper ─────────────────────────
// POST {scraperUrl}/scrape-from-asins — batches up to 50 ASINs per call.
// Returns: seller_id, business_name, VAT number, email, phone, address.
// NOTE: scraperUrl must be reachable from where n8n runs (e.g. http://localhost:8080).
const items = $input.all();
if (!items.length) { console.log('[SCRAPER] No ASINs to scrape'); return []; }

const BATCH_SIZE = 50;

// Group by marketplace
const byMp = {};
for (const it of items) {
  const { asin, seller_name, marketplace: mp, scraperUrl, scraperApiKey } = it.json;
  if (!byMp[mp]) byMp[mp] = { mp, scraperUrl, scraperApiKey, asins: [] };
  byMp[mp].asins.push({ asin, category: seller_name || '', category_path: '' });
}

const allResults = [];

for (const [mpKey, grp] of Object.entries(byMp)) {
  const { asins, scraperUrl, scraperApiKey } = grp;
  const totalBatches = Math.ceil(asins.length / BATCH_SIZE);

  for (let i = 0; i < asins.length; i += BATCH_SIZE) {
    const batch     = asins.slice(i, i + BATCH_SIZE);
    const batchNum  = Math.floor(i / BATCH_SIZE) + 1;

    console.log(`[SCRAPER] ${mpKey} batch ${batchNum}/${totalBatches} — ${batch.length} ASINs`);
    console.log(`[SCRAPER] ASINs: ${batch.map(a => a.asin).join(', ')}`);

    try {
      let resp = await this.helpers.httpRequest({
        method:  'POST',
        url:     `${scraperUrl}/scrape-from-asins`,
        headers: { 'x-api-key': scraperApiKey, 'Content-Type': 'application/json' },
        body:    JSON.stringify({ asins: batch, marketplace: mpKey }),
        timeout: 1800000,
      });
      if (typeof resp === 'string') resp = JSON.parse(resp);

      const results = resp.results || [];
      const ok = results.filter(r => r.status === 'success').length;
      console.log(`[SCRAPER] batch ${batchNum}: ${ok}/${results.length} success`);

      for (const r of results) {
        allResults.push({
          json: {
            asin:           r.asin           || '',
            seller_id:      r.seller_id      || '',
            marketplace:    r.marketplace    || mpKey,
            status:         r.status         || '',
            business_name:  r.business_name  || '',
            email:          r.email          || '',
            phone:          r.phone          || '',
            vat_number:     r.vat_number     || '',
            address:        r.address || r.raw_info || '',
            storefront_url: r.storefront_url || '',
            seller_rating:  r.rating         || '',
            category:       r.category       || '',
            error:          r.error          || '',
          },
        });
      }
    } catch (e) {
      console.error(`[SCRAPER] ${mpKey} batch ${batchNum} failed: ${e.message}`);
      for (const a of batch) {
        allResults.push({ json: { asin: a.asin, marketplace: mpKey, status: 'error', error: e.message } });
      }
    }
  }
}

console.log(`[SCRAPER] Total results: ${allResults.length}`);
return allResults;
